        /// The number of runs started by this schedule.
        /// </summary>
        [Input("startedRunCount")]
        public Input<string>? StartedRunCount { get; set; }

        /// <summary>
        /// The state of this Schedule. Possible values: ACTIVE PAUSED COMPLETED
        /// </summary>
        [Input("state")]
        public Input<string>? State { get; set; }

        /// <summary>
        /// Timestamp when this Schedule was updated.
        /// </summary>
        [Input("updateTime")]
        public Input<string>? UpdateTime { get; set; }

        public AiScheduleState()
        {
        }
        public static new AiScheduleState Empty => new AiScheduleState();
    }
}
